INSERT INTO questions (lesson_id, difficulty, question_type, enunciado, conteudo_pergunta, resposta_correta, explanation) VALUES (15, 'dificil', 10, 'Escucha la sequência de ações digitais cotidianas e pratica tu fluidez no laboratório.', '{"speech_text":"O aplicativo está salvando as fotos enquanto o aparelho está carregando."}', 'O aplicativo está salvando as fotos enquanto o aparelho está carregando.', 'Desafio duplo de gerúndio (''salvando'', ''carregando'') conectado pela estrutura simultânea ''enquanto''.');
